mapper.update:
UPDATE student SET
name=#{name},
no=#{no},
gender=#{gender},
phone=#{phone},
degree=#{degree},
clazz_id=#{clazzId},
violation_count=#{violationCount},
violation_score= #{violationScore},
update_time= NOW()
,id_card=#{idCard}
,is_college=#{isCollege}
,address=#{address}
,graduation_date=#{graduationDate}
WHERE id=#{id}

mapper.select:
SELECT student.id, student.name, student.no, student.gender, student.phone, student.id_card, student.is_college, student.address, student.degree, student.graduation_date, student.clazz_id, student.violation_count, student.violation_score, student.create_time, student.update_time, clazz.name AS clazzName
FROM student LEFT JOIN clazz ON student.clazz_id = clazz.id
AND student.name LIKE CONCAT('%',#{name},'%')
AND student.degree = #{degree}
AND student.clazz_id = #{clazzId}
